using ModelContextProtocol.Server;
using Microsoft.Extensions.Logging;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from an external API by its unique identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);

        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Successfully fetched resource {Id}", id);
        return content;
    }

    [McpServerTool, Description("Search for resources matching a query string.")]
    public async Task<string> SearchResources(
        [Description("The search query to filter resources")] string query,
        [Description("Maximum number of results to return (default: 10)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources with query '{Query}', max {Max}", query, maxResults);

        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={maxResults}",
            cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

